startingCSS:
.list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.item {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 1rem;
  background: white;
  border: 2px solid #e2e8f0;
  border-radius: 8px;
  transition: background 0.15s, border-color 0.15s;
}

label {
  cursor: pointer;
  font-weight: 500;
  color: #374151;
}

input[type="checkbox"] {
  width: 18px;
  height: 18px;
  accent-color: #a855f7;
  cursor: pointer;
  flex-shrink: 0;
}
